#!/bin/bash

# Create Pivot Table for Q2 Revenue Analysis by Region
# Usage: ./create_pivot_table.sh <SPREADSHEET_URL>

SHEET_URL="${1:-https://docs.google.com/spreadsheets/d/1xyz789/edit}"

echo "Creating pivot table for Q2 revenue analysis..."

# Step 1: Get spreadsheet metadata to find the source sheet ID
echo "Fetching spreadsheet metadata..."
METADATA=$(gsheets get "$SHEET_URL" --json 2>/dev/null)

if [ $? -ne 0 ]; then
    echo "Error: Could not access spreadsheet. Please check the URL and permissions."
    exit 1
fi

# Extract the first sheet ID (assuming data is on the first sheet)
SOURCE_SHEET_ID=$(echo "$METADATA" | jq -r '.sheets[0].properties.sheetId')
SPREADSHEET_ID=$(echo "$METADATA" | jq -r '.spreadsheetId')

echo "Source Sheet ID: $SOURCE_SHEET_ID"
echo "Spreadsheet ID: $SPREADSHEET_ID"

# Step 2: Create a new sheet for the pivot table
echo "Creating new sheet for pivot table..."
NEW_SHEET_RESPONSE=$(gsheets format batch-update "$SHEET_URL" --data '[{
  "addSheet": {
    "properties": {
      "title": "Q2 Revenue Pivot - By Region",
      "gridProperties": {
        "rowCount": 100,
        "columnCount": 20
      }
    }
  }
}]' --json 2>/dev/null)

PIVOT_SHEET_ID=$(echo "$NEW_SHEET_RESPONSE" | jq -r '.replies[0].addSheet.properties.sheetId')
echo "Pivot Sheet ID: $PIVOT_SHEET_ID"

# Step 3: Create the pivot table
# This assumes your data has columns:
# Column 0 (A): Date
# Column 1 (B): Region
# Column 2 (C): Revenue
# Adjust the column indices based on your actual data structure

cat > /tmp/pivot_request.json <<'EOF'
[
  {
    "updateCells": {
      "rows": [
        {
          "values": [
            {
              "pivotTable": {
                "source": {
                  "sheetId": SOURCE_SHEET_ID_PLACEHOLDER,
                  "startRowIndex": 0,
                  "startColumnIndex": 0,
                  "endRowIndex": 1000,
                  "endColumnIndex": 10
                },
                "rows": [
                  {
                    "sourceColumnOffset": 1,
                    "showTotals": true,
                    "sortOrder": "ASCENDING"
                  }
                ],
                "values": [
                  {
                    "summarizeFunction": "SUM",
                    "sourceColumnOffset": 2,
                    "name": "Total Revenue"
                  }
                ],
                "valueLayout": "HORIZONTAL"
              }
            }
          ]
        }
      ],
      "fields": "pivotTable",
      "start": {
        "sheetId": PIVOT_SHEET_ID_PLACEHOLDER,
        "rowIndex": 0,
        "columnIndex": 0
      }
    }
  }
]
EOF

# Replace placeholders with actual IDs
sed -i "s/SOURCE_SHEET_ID_PLACEHOLDER/$SOURCE_SHEET_ID/g" /tmp/pivot_request.json
sed -i "s/PIVOT_SHEET_ID_PLACEHOLDER/$PIVOT_SHEET_ID/g" /tmp/pivot_request.json

echo "Creating pivot table..."
gsheets format batch-update "$SHEET_URL" --data @/tmp/pivot_request.json

if [ $? -eq 0 ]; then
    echo "✓ Pivot table created successfully!"
    echo "✓ View it in the 'Q2 Revenue Pivot - By Region' tab"
    echo ""
    echo "Spreadsheet URL: https://docs.google.com/spreadsheets/d/$SPREADSHEET_ID/edit"
else
    echo "✗ Error creating pivot table. Check your data structure."
    exit 1
fi

# Clean up
rm -f /tmp/pivot_request.json

